export function parseDateForNavigation(
  value: string,
  refDate: Date = newDate(),
): Date | null {
  if (!value) return null;

  // Try to extract a 4-digit year from the input
  const yearMatch = value.match(/\b(1\d{3}|2\d{3})\b/);
